console.log('Funksiya elan nümunəsi...');
function sayHello() {
    console.log('Salam, Dünya!');
}
sayHello();
// Output:
// Funksiya elan nümunəsi...
// Salam, Dünya!

console.log('Parametrlər və return nümunəsi...');
function addNumbers(a, b) {
    const sum = a + b;
    return sum;
}
const result = addNumbers(5, 3);
console.log('Nəticə:', result);
// Output:
// Parametrlər və return nümunəsi...
// Nəticə: 8

console.log('Hoisting nümunəsi...');
greet(); // İşləyir
function greet() {
    console.log('Salam!');
}
// Output:
// Hoisting nümunəsi...
// Salam!

console.log('Funksiya scope-u nümunəsi...');
function showMessage() {
    const message = 'Funksiya daxilində';
    console.log(message);
}
showMessage();
// console.log(message); // Səhv: message is not defined
// Output:
// Funksiya scope-u nümunəsi...
// Funksiya daxilində

console.log('var, let, const ilə funksiya nümunəsi...');
function example() {
    var varValue = 'Var dəyəri';
    let letValue = 'Let dəyəri';
    const constValue = 'Const dəyəri';
    console.log(varValue, letValue, constValue);
}
example();
// Output:
// var, let, const ilə funksiya nümunəsi...
// Var dəyəri Let dəyəri Const dəyəri

console.log('Səhvə yol açan nümunə...');
function calculateArea(width, height) {
    const area = width * height;
    // return area; // Unutqan return
}
const result = calculateArea(4, 5);
console.log('Nəticə:', result);
// Output:
// Səhvə yol açan nümunə...
// Nəticə: undefined

